   import 'dart:convert';
   import 'dart:typed_data';

   /// Encodes a PNG screenshot for Anthropic image blocks and OpenAI image_url
   /// parts. Pure Dart; no dart:io.
   class VisionImage {
     final String base64Png;
     const VisionImage._(this.base64Png);
     factory VisionImage.fromPngBytes(Uint8List bytes) =>
         VisionImage._(base64Encode(bytes));
     Map<String, dynamic> toAnthropicBlock() => {
       'type': 'image',
       'source': {'type': 'base64', 'media_type': 'image/png', 'data': base64Png},
     };
     Map<String, dynamic> toOpenAiPart() => {
       'type': 'image_url',
       'image_url': {'url': 'data:image/png;base64,\$base64Png'},
     };
   }
   ```

   `tool_helpers.dart`:
   ```dart
   import 'package:json_schema/json_schema.dart';
   import '../types.dart';

   String encodeToolName(String dotted) => dotted.replaceAll('.', '_');
   String decodeToolName(String wire, List<ToolDescriptor> tools) =>
       lookupTool(tools, wire)?.name ?? wire;

   ToolDescriptor? lookupTool(List<ToolDescriptor> tools, String wireName) {
     for (final t in tools) {
       if (encodeToolName(t.name) == wireName) return t;
     }
     return null;
   }

   /// Validates [args] against [tool.inputSchema] (draft-07).
   /// Throws SchemaRejection on mismatch.
   void validateToolArgs(ToolDescriptor tool, Map<String, dynamic> args) {
     final r = JsonSchema.create(tool.inputSchema,
         schemaVersion: SchemaVersion.draft7).validate(args);
     if (!r.isValid) {
       throw SchemaRejection(
         validationError: r.errors.map((e) => e.toString()).join('; '),
         rawOutput: args.toString(),
       );
     }
   }
   ```

