   - 'two rejects then valid ‚Üí retries=2, rejections.length==2'
   - 'four rejects ‚Üí throws InvalidActionExhausted with 3 rejections'
   - 'one schema rejection then valid ‚Üí succeeds'
   - 'two schema rejections ‚Üí throws SchemaExhausted'

