   class ValidationReject extends ValidationResult {
     final String reason, tool, description;
     final List<String>? expected;   // for unknown_tool
     final Object? got;              // unknown_tool, schema_invalid, node_*
     final String? pointer;          // JSON Pointer for schema_invalid, node_*
     const ValidationReject({required this.reason, required this.tool,
       required this.description, this.expected, this.got, this.pointer});

     /// Stable key order: tool, reason, description, pointer?, expected?, got?.
     String toModelMessage() {
       final m = <String, Object?>{'tool': tool, 'reason': reason,
         'description': description};
       if (pointer != null) m['pointer'] = pointer;
       if (expected != null) m['expected'] = expected;
       if (got != null) m['got'] = got;
       return jsonEncode(m);
     }
   }
