3. `ActionValidator` three-pass impl ‚Äî `packages/exploration_agent/lib/src/validation/action_validator.dart`

   ```dart
   import 'package:json_schema/json_schema.dart';
   import '../observation/models.dart' show Observation, SemanticsNode;
   import '../provider/types.dart' show ToolDescriptor;
   import 'core_targets.dart';
   import 'result.dart';

   class ActionValidator {
     const ActionValidator();

     ValidationResult validate({
       required ({String tool, Map<String, Object?> args}) action,
       required Observation observation,
       required List<ToolDescriptor> tools,
     }) {
       // Pass 1 ‚Äî tool name.
       final desc = tools.where((t) => t.name == action.tool).firstOrNull;
       if (desc == null) {
         final names = tools.map((t) => t.name).toList()..sort();
         return ValidationReject(reason: 'unknown_tool', tool: action.tool,
           description: 'unknown tool: ${action.tool}. available: ${names.join(', ')}',
           expected: names, got: action.tool);
       }
       // Pass 2 ‚Äî args schema (json_schema draft-07).
       final r = JsonSchema.create(desc.inputSchema, schemaVersion: SchemaVersion.draft7)
         .validate(action.args);
       if (!r.isValid) {
         final e = r.errors.first;
         return ValidationReject(reason: 'schema_invalid', tool: action.tool,
           description: _humanize(e),
           pointer: e.instancePath.isEmpty ? '/' : e.instancePath,
           got: action.args);
       }
       // Pass 3 ‚Äî node existence/enabled/visible for core node-targeting tools.
       final keys = coreNodeTargetingTools[action.tool];
       if (keys != null) {
         for (final key in keys) {
           final id = action.args[key];
           if (id is! int) {
             return ValidationReject(reason: 'schema_invalid', tool: action.tool,
               description: '$key must be int, got ${id.runtimeType}',
               pointer: '/$key', got: id);
           }
           final node = observation.core.nodes[id];
           if (node == null) return _nr('node_not_found', action.tool, key, id,
             '$key=$id not in current semantics tree');
           if (!node.enabled) return _nr('node_disabled', action.tool, key, id,
             '$key=$id is disabled');
           if (!node.visible) return _nr('node_not_visible', action.tool, key, id,
             '$key=$id is off-screen / not visible');
         }
       }
       return const ValidationOk();
     }

     ValidationReject _nr(String reason, String tool, String key, int id, String d) =>
       ValidationReject(reason: reason, tool: tool, description: d,
         pointer: '/$key', got: id);

     /// Compress a json_schema ValidationError into one human line.
     /// Patterns from json_schema 5.x:
     ///   "required prop 'X' missing"  -> "missing required field 'X'"
     ///   "type: wanted T"             -> "<field> must be T"
     /// Fallback: "<path>: <raw>".
     String _humanize(ValidationError e) {
       final req = RegExp(r"required prop '([^']+)' missing").firstMatch(e.message);
       if (req != null) return "missing required field '${req.group(1)}'";
       final ty = RegExp(r'type: wanted (\w+)').firstMatch(e.message);
       if (ty != null) {
         final f = e.instancePath.replaceFirst('/', '');
         return '${f.isEmpty ? '<root>' : f} must be ${ty.group(1)}';
       }
       return '${e.instancePath.isEmpty ? '<root>' : e.instancePath}: ${e.message}';
     }
   }
   ```

