4. Implement the differ ‚Äî `exploration_agent/lib/src/observation/observation_differ.dart`

   ```dart
   class ObservationDiffer {
     static ObservationDiff diff(Observation prev, Observation curr) =>
       ObservationDiff(core: _core(prev.core, curr.core),
                       plugins: _plugins(prev.plugins, curr.plugins));

     static CoreDiff _core(CoreFragment p, CoreFragment c) {
       final added=<SemanticsNode>[], removed=<int>[], changed=<NodeChange>[];
       for (final id in c.nodes.keys) {
         if (!p.nodes.containsKey(id)) added.add(c.nodes[id]!);
         else if (p.nodes[id] != c.nodes[id])
           changed.add(NodeChange(p.nodes[id]!, c.nodes[id]!));
       }
       for (final id in p.nodes.keys) {
         if (!c.nodes.containsKey(id)) removed.add(id);
       }
       added.sort((a,b)=>a.id.compareTo(b.id));
       removed.sort();
       changed.sort((a,b)=>a.curr.id.compareTo(b.curr.id));
       final routes = _listEq(p.routeStack, c.routeStack)
         ? const <RouteChange>[]
         : [RouteChange(previous: p.routeStack, current: c.routeStack)];
       final errs = c.errors.where((e)=>!p.errors.contains(e)).toList();
       return CoreDiff(routeChanges: routes, nodesAdded: added,
         nodesRemoved: removed, nodesChanged: changed, errorsAdded: errs);
     }

     static Map<String, PluginDiff> _plugins(
         Map<String, PluginFragment> p, Map<String, PluginFragment> c) {
       final out = <String, PluginDiff>{};
       for (final ns in c.keys) {
         final cur = c[ns]!; final prev = p[ns];
         if (prev == null) { out[ns] = PluginDiffAdded(cur.data); continue; }
         out[ns] = (cur.deltaFriendly && prev.deltaFriendly)
           ? _structured(prev.data, cur.data)
           : PluginDiffOpaque(previous: prev.data, current: cur.data);
       }
       for (final ns in p.keys) {
         if (!c.containsKey(ns)) out[ns] = PluginDiffRemoved(p[ns]!.data);
       }
       return out;
     }

     static PluginDiffStructured _structured(Map<String,dynamic> a, Map<String,dynamic> b) {
       final added=<String,dynamic>{}, removed=<String,dynamic>{};
       final changed=<String,ChangedValue>{};
       for (final k in b.keys) {
         if (!a.containsKey(k)) added[k]=b[k];
         else if (a[k]!=b[k]) changed[k]=ChangedValue(a[k], b[k]);
       }
       for (final k in a.keys) { if (!b.containsKey(k)) removed[k]=a[k]; }
       return PluginDiffStructured(added: added, removed: removed, changed: changed);
     }
   }
   ```

