   void _registerExtensions(List<ExplorationTool> tools) {
     for (final t in tools) {
       final suffix = t.name.substring('core.'.length);
       developer.registerExtension('ext.flutter.exploration.core.$suffix',
         (method, params) async {
           try {
             final args = jsonDecode(params['args'] ?? '{}') as Map<String,dynamic>;
             final err = t.inputSchema.validate(args);
             if (err != null) {
               return developer.ServiceExtensionResponse.error(400,
                 jsonEncode({'code':'schema_invalid','message': err}));
             }
             final r = await t.call(args);
             return developer.ServiceExtensionResponse.result(jsonEncode(r.toJson()));
           } on CoreToolError catch (e) {
             return developer.ServiceExtensionResponse.result(
               jsonEncode({'ok': false, 'code': e.code, 'message': e.message}));
           }
         });
     }
   }
