   ({RiverpodExplorationPlugin plugin, ProviderContainer container}) wired({
     int budget = 1024,
   }) {
     final seed =
         RiverpodExplorationPlugin(container: ProviderContainer());
     final c = ProviderContainer(observers: [seed.observer]);
     final p = RiverpodExplorationPlugin(
         container: c, observationBudgetBytes: budget);
     // Move the observer onto the real plugin so observer/_c agree.
