       final p = RiverpodExplorationPlugin(container: ProviderContainer());
       expect(await p.observe(oc(0)), isNull);
     });

     test('observe returns null when container is empty', () async {
       final p = RiverpodExplorationPlugin(container: ProviderContainer());
       await p.initialize(ctx());
       expect(await p.observe(oc(1)), isNull);
