     test('lists live providers, records change, and tool invalidates',
         () async {
       final counter = StateProvider<int>((r) => 0, name: 'counter');
       final c = ProviderContainer();
       addTearDown(c.dispose);
       final plugin = RiverpodExplorationPlugin(container: c);
       // Wire observer by recreating container with it.
       final c2 = ProviderContainer(observers: [plugin.observer]);
       addTearDown(c2.dispose);
       final p2 = RiverpodExplorationPlugin(container: c2);
       // Move observer onto p2 explicitly: they share by re-using.
       p2.observer.clear();
       c2.read(counter);
       await p2.initialize(ctx());
       c2.read(counter.notifier).state = 1;
       final frag = await p2.observe(oc(3));
       expect(frag, isNotNull);
       expect(frag!['invalidatable_providers'], contains('counter'));
       final ch = frag['recent_state_changes'] as List;
       expect(ch.any((e) => (e as Map)['provider_id'] == 'counter' &&
