5. `ThinkingPanel` widget ‚Äî `packages/exploration_devtools/lib/src/thinking/thinking_panel.dart` (created)

   Stateful widget. Single leaf `ValueListenableBuilder<int>` over `_ctl.text` rebuilds only the `SelectableText`. `NotificationListener<ScrollUpdateNotification>` pauses auto-scroll on negative scrollDelta when not at bottom. On text change, post-frame `jumpTo(maxScrollExtent)` if `autoScroll` is on. `Jump to live` FAB visible only when paused.

   ```dart
   import 'package:exploration_agent/exploration_agent.dart';
   import 'package:flutter/material.dart';
   import 'thinking_panel_controller.dart';
   class ThinkingPanel extends StatefulWidget {
     const ThinkingPanel({super.key, required this.session});
     final ExplorationSession session;
     @override State<ThinkingPanel> createState() => _ThinkingPanelState();
   }
   class _ThinkingPanelState extends State<ThinkingPanel> {
     late final ThinkingPanelController _ctl = ThinkingPanelController(widget.session)..start();
     final ScrollController _scroll = ScrollController();
     @override void initState() { super.initState(); _ctl.text.addListener(_onText); }
     void _onText() {
       if (!_ctl.autoScroll.value) return;
       WidgetsBinding.instance.addPostFrameCallback((_) {
         if (_scroll.hasClients) _scroll.jumpTo(_scroll.position.maxScrollExtent);
       });
     }
     bool _onScroll(ScrollUpdateNotification n) {
       if (!_ctl.autoScroll.value) return false;
       final atBottom = n.metrics.pixels >= n.metrics.maxScrollExtent - 4;
       if ((n.scrollDelta ?? 0) < 0 && !atBottom) _ctl.pauseAutoScroll();
       return false;
     }
     @override void dispose() {
       _ctl.text.removeListener(_onText); _scroll.dispose(); _ctl.dispose(); super.dispose();
     }
     @override Widget build(BuildContext context) => Stack(children: [
       Positioned.fill(child: NotificationListener<ScrollUpdateNotification>(
         onNotification: _onScroll,
         child: ValueListenableBuilder<int>(
           valueListenable: _ctl.text,
           builder: (_, __, ___) => SingleChildScrollView(
             controller: _scroll, padding: const EdgeInsets.all(8),
             child: SelectableText(_ctl.text.text,
               style: const TextStyle(fontFamily: 'monospace', fontSize: 12)),
           )))),
       ValueListenableBuilder<bool>(
         valueListenable: _ctl.autoScroll,
         builder: (_, on, __) => on ? const SizedBox.shrink()
           : Positioned(right: 12, bottom: 12, child: FloatingActionButton.extended(
               key: const Key('jump-to-live'),
               onPressed: () {
                 _ctl.resumeAutoScroll();
                 if (_scroll.hasClients) _scroll.jumpTo(_scroll.position.maxScrollExtent);
               },
               icon: const Icon(Icons.arrow_downward),
               label: const Text('Jump to live'))),
       ),
     ]);
   }
   ```
