   `lib/src/run.dart`:
   ```dart
   import 'dart:async';
   import 'dart:io';
   import 'package:exploration_agent/exploration_agent.dart';
   import 'package:exploration_agent/loop.dart' show LoopDriver;
   import 'cli_args.dart';
   import 'file_trajectory_sink.dart';
   import 'provider_factory.dart';

   const _agentsMd = 'exploration_cli/templates/AGENTS.md';

   Future<int> runCli(List<String> argv,
       {required Stdin stdin, required Stdout stdout, required IOSink stderr}) async {
     if (argv.contains('-h') || argv.contains('--help')) {
       stdout.writeln(buildParser().usage);
       stdout.writeln('\nAGENTS.md template: $_agentsMd');
       return 0;
     }
     final CliArgs args;
     try { args = parseCliArgs(argv); }
     on CliUsageError catch (e) {
       stderr.writeln('error: ${e.message}');
       stderr.writeln(buildParser().usage);
       return 64;
     }
     String? goal = args.goal;
     if (goal == null) {
       if (stdin.hasTerminal) {
         stderr.writeln('error: --goal not provided and stdin is a TTY'); return 64;
       }
       goal = (await stdin.transform(systemEncoding.decoder).join()).trim();
       if (goal.isEmpty) { stderr.writeln('error: empty goal'); return 64; }
     }
     final outPath = args.outputPath ?? FileTrajectorySink.defaultOutputPath();
     final sink = await FileTrajectorySink.open(outPath);
     final writer = TrajectoryWriter(sink); // .19
     final provider = buildProvider(args.tier);
     final session = await ExplorationSession.connect(args.vmUri);
     final sub = session.progress.listen((e) => _render(stdout, e));
     try {
       await session.start(goal, ExplorationConfig());
       final driver = LoopDriver(session: session, provider: provider, writer: writer,
         pluginNamespaces: args.plugins, policy: args.policy.name);
       final outcome = await driver.run();
       if (outcome.harnessError != null) {
         stderr.writeln('harness_error: ${outcome.harnessError}'); return 1;
       }
       return 0;
     } finally {
       await sub.cancel(); await session.end(); await writer.close();
     }
   }

   void _render(Stdout out, SessionProgressEvent e) {
     out.writeln(switch (e) {
       SessionStarted(:final goal) => '[session] started: $goal',
       TurnBegan(:final turn) => '[turn $turn] begin',
       PluginAutoDisabled(:final namespace, :final reason) =>
         '[plugin] auto-disabled $namespace ($reason)',
       SessionEnded() => '[session] ended',
     });
   }
   ```

   `LoopDriver` parameters and `run() ‚Üí LoopOutcome { harnessError? }` shape match .18's committed Approach. If .18 lands with different names, this file is the only callsite to update.

