   ```dart
   import 'token_counter.dart';

   class SummaryOversizeError implements Exception {
     final int tokenCount;
     final int hardCap;
     const SummaryOversizeError(this.tokenCount, this.hardCap);
     @override
     String toString() =>
         'SummaryOversizeError: \$tokenCount tokens > hard cap \$hardCap';
   }

   class RunningSummary {
     static const int defaultSoftCap = 500;
     static const int defaultHardCap = 1000;
     final TokenCounter _counter;
     final int softCap;
     final int hardCap;
     String _text = '';
     int _tokens = 0;

     RunningSummary({
       required TokenCounter counter,
       this.softCap = defaultSoftCap,
       this.hardCap = defaultHardCap,
     })  : _counter = counter,
          assert(softCap > 0 && hardCap >= softCap);

     String get text => _text;
     int get tokens => _tokens;
     bool get softCapExceeded => _tokens > softCap;

     /// Replaces summary; throws [SummaryOversizeError] above hard cap;
     /// state unchanged on throw.
     void update(String text) {
       final n = _counter.count(text);
       if (n > hardCap) throw SummaryOversizeError(n, hardCap);
       _text = text;
       _tokens = n;
     }
   }
   ```

