   ```dart
   class ExecutedAction {
     final String tool;
     final Map<String, Object?> args;
     final String oneLine; // verbatim line included in prompt
     const ExecutedAction(
         {required this.tool, required this.args, required this.oneLine});
   }

   class ActionRing {
     static const int defaultCapacity = 5;
     final int capacity;
     final List<ExecutedAction> _buf = <ExecutedAction>[];

     ActionRing({this.capacity = defaultCapacity}) : assert(capacity > 0);

     void push(ExecutedAction a) {
       _buf.add(a);
       if (_buf.length > capacity) {
         _buf.removeRange(0, _buf.length - capacity);
       }
     }

     List<ExecutedAction> get entries => List.unmodifiable(_buf);
   }
   ```

