   ```dart
   import '../memory/action_ring.dart';
   import '../memory/running_summary.dart';
   import 'prompt_payload.dart';

   /// Pure assembler. [mergedTools] is consumed as-is each call; never cached.
   /// Plugin enable/disable flows into the next call without invalidation
   /// (PRD ¬ß10 step 5, ¬ß16.2).
   class PromptAssembler {
     const PromptAssembler();

     PromptPayload assemble({
       required String agentsMd,
       required String goal,
       required RunningSummary summary,
       required List<ExecutedAction> actions,
       required String observation,
       required String diff,
       required List<ToolDefinition> mergedTools,
     }) {
       final system = PromptMessage(role: 'system', content: agentsMd);
       final actionLines = actions.map((a) => a.oneLine).join('\n');
       final body = StringBuffer()
         ..writeln('# Goal')..writeln(goal)..writeln()
         ..writeln('# Running Summary')..writeln(summary.text)..writeln()
         ..writeln('# Last Actions')..writeln(actionLines)..writeln()
         ..writeln('# Observation')..writeln(observation)..writeln()
         ..writeln('# Diff')..writeln(diff);
       final user = PromptMessage(role: 'user', content: body.toString());
       // Defensive copy: caller mutating their list afterwards must not
       // change an already-emitted payload.
       final tools = List<ToolDefinition>.unmodifiable(mergedTools);
       return PromptPayload(messages: [system, user], tools: tools);
     }
   }
   ```

