1. Create `ErrorRingBuffer` ‚Äî `exploration_flutter/lib/src/errors/error_ring_buffer.dart`

   Bounded ring with monotonic seq + since-cursor. Pure Dart, no Flutter imports.

   ```dart
   import 'dart:collection';

   class ErrorEntry {
     final int seq;
     final String message;
     final List<String> frames; // <= 5
     final int wallClockOffsetMs;
     const ErrorEntry({required this.seq, required this.message,
         required this.frames, required this.wallClockOffsetMs});
     Map<String, Object?> toJson() => {'seq': seq, 'message': message,
         'frames': frames, 'wallClockOffsetMs': wallClockOffsetMs};
   }

   class ErrorRingBuffer {
     ErrorRingBuffer({this.capacity = 50, required this.sessionStart})
         : assert(capacity > 0), _entries = Queue<ErrorEntry>();
     final int capacity;
     final DateTime sessionStart;
     final Queue<ErrorEntry> _entries;
     int _nextSeq = 1;

     ErrorEntry record({required String message, required Iterable<String> rawFrames}) {
       final entry = ErrorEntry(seq: _nextSeq++, message: message,
           frames: rawFrames.take(5).toList(growable: false),
           wallClockOffsetMs:
               DateTime.now().difference(sessionStart).inMilliseconds);
       _entries.addLast(entry);
       while (_entries.length > capacity) _entries.removeFirst();
       return entry;
     }

     ({List<ErrorEntry> entries, int cursor}) since(int since) {
       final out = [for (final e in _entries) if (e.seq > since) e];
       return (entries: out, cursor: out.isEmpty ? since : out.last.seq);
     }
   }
   ```

