4. Wire error capture into `ExplorationBinding` ‚Äî `exploration_flutter/lib/src/binding.dart`

   Extend `ensureInitialized` (cx6.2) with `int errorBufferCapacity = 50`. Inside the existing `kDebugMode` branch, *after* `pluginRegistry.initializeAll()`, call `_installErrorCapture(capacity: errorBufferCapacity)` then `_registerErrorVmExtension()`. Both no-op via `_errorHooksInstalled` guard so repeated `ensureInitialized` does not re-hook. Plugin chain uses cx6.3's `pluginRegistry.entries` (registration order) and `recordStrike` for throwing handlers.

   ```dart
   late final ErrorRingBuffer _errorBuffer;
   bool _errorHooksInstalled = false;
   FlutterExceptionHandler? _priorFlutterOnError;
   ErrorCallback? _priorPlatformOnError;

   ErrorRingBuffer get errorBuffer => _errorBuffer; // for cx6.8

   void _installErrorCapture({required int capacity}) {
     if (_errorHooksInstalled) return;
     _errorHooksInstalled = true;
     _errorBuffer = ErrorRingBuffer(capacity: capacity, sessionStart: sessionStart);

     _priorFlutterOnError = FlutterError.onError;
     FlutterError.onError = (d) {
       _captureError(message: d.exceptionAsString(), stack: d.stack);
       _priorFlutterOnError?.call(d);
     };
     _priorPlatformOnError = PlatformDispatcher.instance.onError;
     PlatformDispatcher.instance.onError = (e, s) {
       _captureError(message: e.toString(), stack: s);
       return _priorPlatformOnError?.call(e, s) ?? false;
     };
   }

   void _captureError({required String message, StackTrace? stack}) {
     for (final entry in pluginRegistry.entries) {
       final h = entry.errorHandler;
       if (h == null) continue;
       try { h(message, stack); }
       catch (e, st) {
         pluginRegistry.recordStrike(entry,
             method: 'errorHandler', error: e, stack: st);
       }
     }
     _errorBuffer.record(message: message, rawFrames: firstFiveFrames(stack));
   }
   ```

